{"meta": null, "content": [{"type": "text", "text": "{"content":"1735: \n1736:   /// Return the EVT corresponding to this LLVM type.  This is fixed by the LLVM\n1737:   /// operations except for the pointer size.  If AllowUnknown is true, this\n1738:   /// will return MVT::Other for types with no EVT counterpart (e.g. structs),\n1739:   /// otherwise it will assert.\n1740:   EVT getValueType(const DataLayout \u0026DL, Type *Ty,\n1741:                    bool AllowUnknown = false) const {\n1742:     // Lower scalar pointers to native pointer types.\n1743:     if (auto *PTy = dyn_cast\u003cPointerType\u003e(Ty))\n1744:       return getPointerTy(DL, PTy-\u003egetAddressSpace());\n1745: \n1746:     if (auto *VTy = dyn_cast\u003cVectorType\u003e(Ty)) {\n1747:       Type *EltTy = VTy-\u003egetElementType();\n1748:       // Lower vectors of pointers to native pointer types.\n1749:       EVT EltVT;\n1750:       if (auto *PTy = dyn_cast\u003cPointerType\u003e(EltTy))\n1751:         EltVT = getPointerTy(DL, PTy-\u003egetAddressSpace());\n1752:       else\n1753:         EltVT = EVT::getEVT(EltTy, false);\n1754:       return EVT::getVectorVT(Ty-\u003egetContext(), EltVT, VTy-\u003egetElementCount());\n1755:     }\n1756: \n1757:     return EVT::getEVT(Ty, AllowUnknown);\n1758:   }\n1759: \n1760:   EVT getMemValueType(const DataLayout \u0026DL, Type *Ty,\n1761:                       bool AllowUnknown = false) const {\n1762:     // Lower scalar pointers to native pointer types.\n1763:     if (auto *PTy = dyn_cast\u003cPointerType\u003e(Ty))\n1764:       return getPointerMemTy(DL, PTy-\u003egetAddressSpace());\n1765: \n1766:     if (auto *VTy = dyn_cast\u003cVectorType\u003e(Ty)) {\n1767:       Type *EltTy = VTy-\u003egetElementType();\n1768:       EVT EltVT;\n1769:       if (auto *PTy = dyn_cast\u003cPointerType\u003e(EltTy))\n1770:         EltVT = getPointerMemTy(DL, PTy-\u003egetAddressSpace());\n1771:       else\n1772:         EltVT = EVT::getEVT(EltTy, false);\n1773:       return EVT::getVectorVT(Ty-\u003egetContext(), EltVT, VTy-\u003egetElementCount());\n1774:     }\n1775: \n1776:     return getValueType(DL, Ty, AllowUnknown);\n1777:   }\n1778: \n1779: \n1780:   /// Return the MVT corresponding to this LLVM type. See getValueType.\n1781:   MVT getSimpleValueType(const DataLayout \u0026DL, Type *Ty,\n1782:                          bool AllowUnknown = false) const {\n1783:     return getValueType(DL, Ty, AllowUnknown).getSimpleVT();\n1784:   }\n1785: \n1786:   /// Returns the desired alignment for ByVal or InAlloca aggregate function\n1787:   /// arguments in the caller parameter area.\n1788:   virtual Align getByValTypeAlignment(Type *Ty, const DataLayout \u0026DL) const;\n1789: \n1790:   /// Return the type of registers that this ValueType will eventually require.\n1791:   MVT getRegisterType(MVT VT) const {\n1792:     assert((unsigned)VT.SimpleTy \u003c std::size(RegisterTypeForVT));\n1793:     return RegisterTypeForVT[VT.SimpleTy];\n1794:   }\n1795: \n1796:   /// Return the type of registers that this ValueType will eventually require.\n1797:   MVT getRegisterType(LLVMContext \u0026Context, EVT VT) const {\n1798:     if (VT.isSimple())\n1799:       return getRegisterType(VT.getSimpleVT());\n1800:     if (VT.isVector()) {\n1801: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/llvm-project--a8f3c97d@4152de6435984e9fc55431f4d74a7470d8ac05c0/-/blob/llvm/include/llvm/CodeGen/TargetLowering.h%3FL1735-1800"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1735: 
