ID_SIMPLE_VALUE_TYPE)\n52:         return LLVMTy != VT.LLVMTy;\n53:       return false;\n54:     }\n55: \n56:     /// Returns the EVT that represents a floating-point type with the given\n57:     /// number of bits. There are two floating-point types with 128 bits - this\n58:     /// returns f128 rather than ppcf128.\n59:     static EVT getFloatingPointVT(unsigned BitWidth) {\n60:       return MVT::getFloatingPointVT(BitWidth);\n61: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/llvm-project--a8f3c97d@4152de6435984e9fc55431f4d74a7470d8ac05c0/-/blob/llvm/include/llvm/CodeGen/ValueTypes.h%3FL1-60"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: //===- CodeGen/ValueTypes.h - Low-Level Target independ. types --*- C++ -*-===//
